var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...다이나?","JPN":"……ダイナ？","ENG":"...Daina?","TWN":"……黛娜？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"침입자들은 어디에 있습니까. 아직도 낙원의 내부에 있다면 제가...","JPN":"侵入者はどこですか。まだ楽園の内部にいるのなら、私が……","ENG":"Where are the intruders? If they're still inside the Promised Land, then I should–","TWN":"入侵者在哪裡？如果還在樂園內部，我……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"시끄러워.","JPN":"うるさい。","ENG":"Quiet.","TWN":"閉嘴。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"지금 네 상태로는 그들을 못 막아. 의식 태엽이 돌아가는 것만으로도 기적이라고.","JPN":"今のお前じゃあいつらは止められない。意識ゼンマイが動いているだけで奇跡だ。","ENG":"In your current state, you won't be able to stop them. The fact that your cogitation spring is still turning at all is a miracle.","TWN":"你現在這狀態擋不住他們，能維持意識就已經是奇蹟了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...그럼 그냥 내버려두십시오.","JPN":"……なら、放っておいてください。","ENG":"...Then leave me as I am.","TWN":"……那就請你別管了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"아무것도 할 수 없는데, 뭘 위해 저를 재가동한 겁니까?","JPN":"何もできないのに、何のために私を再起動させたのですか？","ENG":"If I can't do anything, then why did you reactivate me?","TWN":"既然什麼都做不到，為什麼還要重啟我？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"네가 오롯이 낙원을 지키기 위해서 만들어진 거라면, 애초에 네가 감정을 느끼고 사고 하는 것 자체가 제작자의 실수겠지.","JPN":"お前がただ楽園を守るためだけに作られたのなら、そもそもお前が感情を持ち、思考すること自体、製作者の設計ミスだ。","ENG":"If you had truly been made solely to protect the Promised Land, then the very fact that you can feel emotions and think would have been a mistake on your creator's part.","TWN":"如果你被製造的原因只是為了守護樂園，那你有感情、能思考本身就是錯誤。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"하지만 그건 실수가 아냐. 아우드라가 처음 널 만든 이유는 자기랑 닮은 친구를 만들기 위해서였으니까.","JPN":"だがそれはミスじゃない。アウドラが最初にお前を作ったのは友だちを作るためだった。","ENG":"But it wasn't a mistake. Audra made you in the first place because she wanted a friend.","TWN":"但那不是錯誤。奧德拉一開始就是為了交朋友才創造了你。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"낙원이 만들어지고 지켜야 할 것들이 늘어나면서, 그 아인 널 조금씩 바꿔나갔어. 외부의 것들로부터 이곳을 지킬 수 있을 정도로 강하게 말이야.","JPN":"楽園が作られ、守るべきものが増えるにつれて、あの子はお前を少しずつ変えていった。外部からのものからここを守れるように、強く。","ENG":"Once the Promised Land was created and there was more to protect, she began changing you little by little. Making you strong enough to defend this place from outsiders.","TWN":"隨著樂園誕生，要守護的東西越來越多，那孩子才逐漸改造你，讓你強大到足以抵禦外界、守護這裡。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"주인은 모두가 행복한 낙원을 완성하기 위해, 다른 침입자들을 막아야 한다고 합니다.","JPN":"主は皆が幸せな楽園を完成するため、他の侵入者を阻止するべきだと言います。","ENG":"My master says that to complete the Promised Land where everyone can be happy, we must stop the other intruders.","TWN":"主人說為了完成所有人幸福的樂園，必須阻止入侵者。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"하지만 그들의 편에서 싸우는 인형은 우리 역시 침입자라고 하더군요.","JPN":"ですがあちら側で戦う人形は、私たちも侵入者だと言っていました。","ENG":"But that doll fighting on their side says that makes us intruders too.","TWN":"但站在他們那邊的人偶，也說我們才是入侵者。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그들이 자신의 세계를 구하기 위해 싸우듯, 우린 낙원을 지키기 위해 그들의 세계를 부숴야 하지.","JPN":"あいつらが自分たちの世界を救うために戦うのと同じく、私たちは楽園を守るために彼らを傷つけるしかない。","ENG":"Just as those humans fight to save their world, we have to harm them if we want to protect the Promised Land.","TWN":"就像人類為了守護自己的世界而戰，我們若要守護樂園，就必須傷害他們。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"서로의 것을 지키기 위한 싸움은, 피할 수 없는 일인 겁니까?","JPN":"互いのものを守るための戦いは、避けられないことなのですか？","ENG":"Is fighting to protect what belongs to each side... truly unavoidable?","TWN":"為了守護彼此而戰……是無法避免的嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"사람이 둘이어도 싸울 이유가 넘치는데, 세상이 둘이면 오죽하겠어?","JPN":"少なくとも……世界ってのが2つ以上存在すると、そうなるな。","ENG":"At the very least... if more than one world exists, then yes.","TWN":"至少……只要有兩個以上的世界，就會如此。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그래서, 넌 어떻게 하고 싶은데?","JPN":"で、お前はどうしたいんだ？","ENG":"So, what is it that you want to do?","TWN":"所以，你想怎麼做？"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"제가 어떻게 하고 싶은 지가... 중요합니까?","JPN":"私がどうしたいのか……それは重要ですか？","ENG":"What I want to do... matters?","TWN":"我怎麼想……重要嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"야, 인형 대가리.","JPN":"おい、人形。","ENG":"Hey, dummy doll.","TWN":"喂，人偶。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"친구를 위해 뭘 할 수 있는지는, 친구가 아니라 네가 정하는 거야.","JPN":"友だちのために何ができるかは、命令じゃなくてお前が決めることだ。","ENG":"What you can do for a friend isn't decided by an order. It's decided by you.","TWN":"是你自己決定為了朋友要做什麼，不是命令。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"드디어 도착했군요.","JPN":"やっと着きましたね。","ENG":"So we've finally arrived.","TWN":"終於到了。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"황금나무 아래에... 엄청 많은 사람들이 모여서 기도하고 있어.","JPN":"黄金の木の下に……たくさんの人が集まって祈っている。","ENG":"Beneath the Golden Tree... There are so many people gathered here, praying.","TWN":"黃金樹下……聚集了好多在祈禱的人。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그들은 타기리온에게 멸망한 세계의 사람들이에요. 황금나무의 신성이 그들을 이곳 낙원의 주민으로 되살렸죠.","JPN":"彼らはタギリオンに滅ぼされた世界の人たちです。黄金の木の神聖が彼らをこの楽園の住民として蘇らせたんです。","ENG":"They're the people of worlds destroyed by Thagirion. The Golden Tree's Divinity brought them back here as the residents of the Promised Land.","TWN":"那些人是被塔基里翁毀滅世界的人，黃金樹的神性把他們復活成樂園居民。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"타기리온이 죄책감에 그런 호의를 베풀었을 것 같진 않은데. 그 아우드라란 여자의 짓이겠지?","JPN":"タギリオンは罪悪感を感じて善意を施すタイプじゃなさそうだし、あのアウドラって女の仕業でしょ？","ENG":"I doubt Thagirion showed them that kindness out of guilt. That was the doing of that woman, Audra, wasn't it?","TWN":"這不像是塔基里翁出於愧疚做得出來的事，應該是奧德拉吧？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...맞아요. 이곳의 모든 것들은 그녀의 손길에서 비롯됐죠.","JPN":"……そうです。ここのすべては彼女の手から生まれました。","ENG":"...Yes. Everything in this place came from her hands.","TWN":"……沒錯。這裡的一切，都出自她的手。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온이 다른 세상으로부터 빼앗은 가능성을 대가로요.","JPN":"タギリオンが、他の世界から奪ってきた可能性を対価に。","ENG":"At the cost of the possibilities Thagirion took from other worlds.","TWN":"以塔基里翁從其他世界奪取的可能性作為代價。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 사람들. 저흴 발견하면 공격해올까요?","JPN":"あの人たち、私たちに気づいたら攻撃してくるでしょうか。","ENG":"Those people... if they spot us, will they attack?","TWN":"那些人會攻擊我們嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};